import { useEffect, useState } from "react";
import { api, getAuthToken } from "../api";

export default function ShopRegister() {
  const [currentUser, setCurrentUser] = useState(null);
  const [name, setName] = useState("");
  const [area, setArea] = useState("");
  const [rating, setRating] = useState("4.0");
  const [shops, setShops] = useState([]);
  const [selectedShopId, setSelectedShopId] = useState("");
  const [medicines, setMedicines] = useState([]);
  const [medicineId, setMedicineId] = useState(null);
  const [medicineName, setMedicineName] = useState("");
  const [medicinePrice, setMedicinePrice] = useState("");
  const [medicineInStock, setMedicineInStock] = useState(true);
  const [error, setError] = useState("");
  const [message, setMessage] = useState("");

  const resetMedicineForm = () => {
    setMedicineId(null);
    setMedicineName("");
    setMedicinePrice("");
    setMedicineInStock(true);
  };

  const loadData = async () => {
    if (!getAuthToken()) {
      setError("Please login to manage shops.");
      setShops([]);
      return;
    }

    try {
      setError("");
      const [meRes, shopsRes, medicinesRes] = await Promise.all([
        api.get("/auth/me/"),
        api.get("/shops/"),
        api.get("/medicines/?page_size=200"),
      ]);
      const mine = shopsRes.data.filter((shop) => shop.owner === meRes.data.id);
      setCurrentUser(meRes.data);
      setShops(mine);
      setMedicines(Array.isArray(medicinesRes.data) ? medicinesRes.data : (medicinesRes.data.results || []));
      if (!selectedShopId && mine.length > 0) {
        setSelectedShopId(String(mine[0].id));
      }
      if (mine.length === 0) {
        setSelectedShopId("");
      }
    } catch (err) {
      setError("Unable to load your shop data.");
    }
  };

  useEffect(() => {
    loadData();
  }, []);

  const createShop = async () => {
    try {
      setError("");
      setMessage("");
      await api.post("/shops/", { name, area, rating: Number(rating) });
      setName("");
      setArea("");
      setRating("4.0");
      setMessage("Shop registered successfully.");
      loadData();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to create shop.");
    }
  };

  const createOrUpdateMedicine = async () => {
    if (!selectedShopId) {
      setError("Create a shop first to manage medicines.");
      return;
    }

    try {
      setError("");
      setMessage("");
      const payload = {
        shop: Number(selectedShopId),
        name: medicineName,
        price: Number(medicinePrice),
        in_stock: medicineInStock,
      };

      if (medicineId) {
        await api.patch(`/medicines/${medicineId}/`, payload);
        setMessage("Medicine updated.");
      } else {
        await api.post("/medicines/", payload);
        setMessage("Medicine added.");
      }

      resetMedicineForm();
      loadData();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to save medicine.");
    }
  };

  const handleEditMedicine = (medicine) => {
    setMedicineId(medicine.id);
    setSelectedShopId(String(medicine.shop));
    setMedicineName(medicine.name);
    setMedicinePrice(String(medicine.price));
    setMedicineInStock(Boolean(medicine.in_stock));
  };

  const handleDeleteMedicine = async (id) => {
    try {
      setError("");
      setMessage("");
      await api.delete(`/medicines/${id}/`);
      setMessage("Medicine deleted.");
      if (medicineId === id) {
        resetMedicineForm();
      }
      loadData();
    } catch (err) {
      setError(err.response?.data?.detail || "Unable to delete medicine.");
    }
  };

  const managedMedicines = medicines.filter(
    (medicine) => String(medicine.shop) === String(selectedShopId)
  );

  return (
    <div className="page">
      <h2>Shop Registration</h2>
      {error && <p>{error}</p>}
      {message && <p>{message}</p>}
      <input
        placeholder="Shop Name"
        value={name}
        onChange={(e) => setName(e.target.value)}
      />
      <input
        placeholder="Area"
        value={area}
        onChange={(e) => setArea(e.target.value)}
      />
      <input
        placeholder="Rating"
        type="number"
        min="0"
        max="5"
        step="0.1"
        value={rating}
        onChange={(e) => setRating(e.target.value)}
      />
      <button onClick={createShop}>Register Shop</button>

      <h3>Your Shops</h3>
      {shops.map((shop) => (
        <div className="card" key={shop.id}>
          <h3>{shop.name}</h3>
          <p>Area: {shop.area}</p>
          <p>Rating: {shop.rating}</p>
        </div>
      ))}

      <h2>Medicine Inventory</h2>
      <p>
        Managing as: {currentUser ? currentUser.username : "-"}
      </p>
      <select
        value={selectedShopId}
        onChange={(e) => setSelectedShopId(e.target.value)}
      >
        <option value="">Select Shop</option>
        {shops.map((shop) => (
          <option key={shop.id} value={shop.id}>
            {shop.name}
          </option>
        ))}
      </select>
      <input
        placeholder="Medicine Name"
        value={medicineName}
        onChange={(e) => setMedicineName(e.target.value)}
      />
      <input
        placeholder="Price"
        type="number"
        min="0"
        step="0.01"
        value={medicinePrice}
        onChange={(e) => setMedicinePrice(e.target.value)}
      />
      <label>
        <input
          type="checkbox"
          checked={medicineInStock}
          onChange={(e) => setMedicineInStock(e.target.checked)}
        />
        In stock
      </label>
      <div>
        <button onClick={createOrUpdateMedicine}>
          {medicineId ? "Update Medicine" : "Add Medicine"}
        </button>
        {medicineId && <button onClick={resetMedicineForm}>Cancel Edit</button>}
      </div>

      {selectedShopId && managedMedicines.length === 0 && (
        <p>No medicines for this shop yet.</p>
      )}

      {managedMedicines.map((medicine) => (
        <div className="card" key={medicine.id}>
          <h3>{medicine.name}</h3>
          <p>Price: Rs {medicine.price}</p>
          <p>Status: {medicine.in_stock ? "In Stock" : "Out of Stock"}</p>
          <button onClick={() => handleEditMedicine(medicine)}>Edit</button>
          <button onClick={() => handleDeleteMedicine(medicine.id)}>Delete</button>
        </div>
      ))}
    </div>
  );
}
